import { Component, Prop, h, Element, Event, EventEmitter, State, Listen, AttachInternals, Watch, Host } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';
import { ChipStatus } from './wdpr-chip.model';
import { PseudoStates } from '../../models/pseudo-states.model';
import { NotificationTypes } from '../wdpr-notification/wdpr-notification.model';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';

@Component({
  tag: 'wdpr-chip',
  shadow: true,
  formAssociated: true,
})
export class WdprChip {
  @Element() el!: HTMLWdprChipElement;

  @State() private leadingSlot: HTMLElement | null = null;
  @State() private trailingSlot: HTMLElement | null = null;

  @Prop() name?: string;
  @Prop() notificationNumber: number = 0;
  @Prop() notificationType?: NotificationTypes = 'alert';
  @Prop({ reflect: true, mutable: true }) showNotificationBadge: boolean = false;

  @Prop({ attribute: 'a11y-label' }) a11yLabel?: string;
  @Prop({ reflect: true }) disabled: boolean = false;
  @Prop({ mutable: true, reflect: true }) selected: boolean = false;
  @Prop() mode: 'single' | 'multi' = 'multi';

  @Prop({ attribute: 'a11y-controls' }) a11yControls?: string;
  @Prop({ attribute: 'a11y-expanded', mutable: true }) a11yExpanded?: string;
  @Prop({ attribute: 'a11y-haspopup' }) a11yHasPopup?: string;
  @Prop({ attribute: 'a11y-pressed' }) a11yPressed?: string;

  @Prop() variant: 'default' | 'vertical' = 'default';
  @Prop() visualContent: 'icon' | 'media' = 'icon';
  @Prop() mediaSrc?: string;
  @Prop() secondaryLabel?: string;
  @Prop() iconName?: string;

  @Event({ eventName: 'wdprToggle' }) wdprToggle!: EventEmitter<{ selected: boolean }>;
  @Event({ eventName: 'wdprDisabledChange' }) wdprDisabledChange!: EventEmitter<{ disabled: boolean }>;

  @AttachInternals()
  internals!: ElementInternals;

  @Watch('selected')
  onSelectedChange() {
    this._updateFormValue();
  }

  @Watch('disabled')
  onDisabledChange(newValue: boolean) {
    this.wdprDisabledChange.emit({ disabled: newValue });
    this._updateFormValue();
  }

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key === KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement | null)?.blur();

      return;
    }

    if (this.disabled) return;

    if (this.a11yHasPopup && (ev.key === KEYBOARD_KEYS.SPACE || ev.key === KEYBOARD_KEYS.ENTER)) {
      ev.preventDefault();
      this._handleClick();
    }
  }

  @Listen('formreset')
  handleFormReset() {
    this.selected = false;
    this._updateFormValue();
  }

  componentWillLoad() {
    this.updateSlots();
  }

  componentDidLoad() {
    this._updateFormValue();
  }

  private get _isMenuTrigger(): boolean {
    return !!this.a11yHasPopup;
  }

  private get _inputType(): 'button' | 'radio' | 'checkbox' {
    if (this._isMenuTrigger) return 'button';

    return this.mode === 'single' ? 'radio' : 'checkbox';
  }

  private get _isVertical(): boolean {
    return this.variant === 'vertical';
  }

  private _updateFormValue() {
    const shouldSubmit = !this.disabled && !this._isMenuTrigger;
    const formValue = shouldSubmit ? (this.selected ? 'selected' : 'not selected') : null;

    queueMicrotask(() => {
      if (this.internals && this.name != null) {
        this.internals?.setFormValue?.(formValue);
      }
    });

    this._updateValidity();
  }

  private _updateValidity() {
    if (this.disabled) {
      this.internals?.setValidity?.({});

      return;
    }

    const isValid = typeof this.selected === 'boolean';
    const validityError = isValid ? {} : { valueMissing: true };
    const errorMessage = isValid ? '' : 'Selected prop must be a boolean';

    this.internals?.setValidity?.(validityError, errorMessage);
  }

  private _handleMouseDown = (ev: MouseEvent) => {
    ev.preventDefault();
  };

  private _handleClick = (ev?: Event) => {
    if (this.disabled) return;

    if (ev) {
      ev.preventDefault();
      ev.stopPropagation();
    }

    if (this._isMenuTrigger) {
      const expanded = this.a11yExpanded === 'true' ? false : true;
      this.a11yExpanded = expanded ? 'true' : 'false';
    }

    if (this.mode === 'single') {
      this.selected = true;
    } else {
      this.selected = !this.selected;
    }

    this.wdprToggle.emit({ selected: this.selected });
  };

  private _handleInputChange = (ev: Event) => {
    if (this.disabled || this._isMenuTrigger) return;

    const input = ev.target as HTMLInputElement;

    if (this.mode === 'single') {
      this.selected = true;
    } else {
      this.selected = input.checked;
    }

    this.wdprToggle.emit({ selected: this.selected });
  };

  private updateSlots = () => {
    this.leadingSlot = this.el.querySelector('[slot="leading-icon"]');
    this.trailingSlot = this.el.querySelector('[slot="trailing-icon"]');
  };

  private get _accessibleLabel() {
    if (!this.a11yLabel) return undefined;

    if (this.showNotificationBadge && this.selected && this.notificationNumber > 0) {
      const notificationText = this.notificationNumber === 1 ? 'notification' : 'notifications';

      return `${this.a11yLabel}, ${this.notificationNumber} ${notificationText}`;
    }

    return this.a11yLabel;
  }

  get _accessiblePressed() {
    if (this.a11yPressed === 'none') return undefined;

    return this.selected ? 'true' : 'false';
  }

  private get _defaultButtonClass(): string {
    const status: ChipStatus = this.selected ? 'selected' : 'unselected';
    const variant = defaultVariantClasses[status];
    const spacing = this.leadingSlot || this.trailingSlot ? 'gap-100' : null;

    return customTwMerge(defaultBaseButtonClass, spacing, this.disabled ? variant.disabled : [variant.default, variant.hover, variant.active]);
  }

  private get _verticalButtonClass(): string {
    const status: ChipStatus = this.selected ? 'selected' : 'unselected';
    const variant = verticalVariantClasses[status];

    return customTwMerge(verticalBaseButtonClass, this.disabled ? variant.disabled : [variant.default, variant.hover, variant.active]);
  }

  private get _verticalLabelClass(): string {
    return customTwMerge('main-label block w-full line-clamp-2', 'text-component-small font-component-accent leading-component-medium');
  }

  private get _verticalSecondaryLabelClass(): string {
    return customTwMerge('secondary-label block w-full mt-050 line-clamp-1', 'label-xsmall');
  }

  private get _verticalVisualWrapperClass(): string {
    if (this.visualContent === 'media') {
      return 'w-dimension-400 h-dimension-400 shrink-0 overflow-hidden';
    }

    return customTwMerge('w-dimension-400 h-dimension-400 shrink-0 flex items-center justify-center rounded-100');
  }

  private renderInput() {
    const isMenuTrigger = this._isMenuTrigger;
    const inputType = this._inputType;
    const role = isMenuTrigger ? 'button' : this.mode === 'single' ? 'radio' : 'checkbox';

    return (
      <input
        type={inputType}
        role={role}
        checked={!isMenuTrigger && this.selected}
        disabled={this.disabled}
        aria-checked={!isMenuTrigger ? (this.selected ? 'true' : 'false') : undefined}
        aria-disabled={this.disabled ? 'true' : undefined}
        aria-label={this._accessibleLabel}
        aria-controls={isMenuTrigger ? this.a11yControls : undefined}
        aria-expanded={isMenuTrigger ? this.a11yExpanded : undefined}
        aria-haspopup={isMenuTrigger ? this.a11yHasPopup : undefined}
        aria-pressed={isMenuTrigger ? this._accessiblePressed : undefined}
        name={this.name}
        tabIndex={this.disabled ? -1 : 0}
        class="peer sr-only"
        onChange={!isMenuTrigger ? this._handleInputChange : undefined}
      />
    );
  }

  private renderNotificationBadge() {
    if (!this.showNotificationBadge) return null;

    return (
      <span class="absolute -top-125 -right-050">
        <wdpr-notification-indicator size="small" type={this.notificationType} number={this.notificationNumber} decorative />
      </span>
    );
  }

  private renderDefault() {
    return (
      <label class={customTwMerge('relative inline-block', this.disabled ? 'cursor-not-allowed' : 'cursor-pointer')}>
        {this.renderInput()}

        <span
          part="button"
          class={this._defaultButtonClass}
          data-selected={this.selected ? 'true' : 'false'}
          aria-hidden="true"
          onMouseDown={this._handleMouseDown}
          onClick={this._handleClick}
        >
          {this.renderNotificationBadge()}

          {this.leadingSlot && (
            <span part="leading-icon" class={defaultIconClass} aria-hidden="true">
              <slot name="leading-icon" onSlotchange={this.updateSlots} />
            </span>
          )}

          <span part="label" class={defaultLabelClass}>
            <slot />
          </span>

          {this.trailingSlot && (
            <span part="trailing-icon" class={defaultIconClass} aria-hidden="true">
              <slot name="trailing-icon" onSlotchange={this.updateSlots} />
            </span>
          )}
        </span>
      </label>
    );
  }

  private renderVerticalVisual() {
    if (this.visualContent === 'media') {
      return (
        <div class={this._verticalVisualWrapperClass}>
          <wdpr-media src={this.mediaSrc} alt="" fade={true} aspect="square" shape="flat" />
        </div>
      );
    }

    return (
      <div class={this._verticalVisualWrapperClass}>
        <wdpr-icon-library icon={this.iconName} size="large" decorative />
      </div>
    );
  }

  private renderVertical() {
    return (
      <label class={customTwMerge('relative inline-block', this.disabled ? 'cursor-not-allowed' : 'cursor-pointer')}>
        {this.renderInput()}

        <span
          part="button"
          class={this._verticalButtonClass}
          data-selected={this.selected ? 'true' : 'false'}
          aria-hidden="true"
          onMouseDown={this._handleMouseDown}
          onClick={this._handleClick}
        >
          {this.renderNotificationBadge()}

          {this.renderVerticalVisual()}

          <div class="content-wrapper flex w-full flex-col items-start overflow-hidden">
            <div part="label" class={this._verticalLabelClass}>
              <slot />
            </div>

            {this.secondaryLabel && (
              <div part="secondary-label" class={this._verticalSecondaryLabelClass}>
                {this.secondaryLabel}
              </div>
            )}
          </div>
        </span>
      </label>
    );
  }

  render() {
    return <Host>{this._isVertical ? this.renderVertical() : this.renderDefault()}</Host>;
  }
}

const defaultBaseButtonClass = `relative inline-flex items-center justify-center rounded-pill border border-solid transition-colors
  select-none p-125
  peer-focus-visible:outline peer-focus-visible:outline-037 peer-focus-visible:outline-stroke-actionable-alt-focused peer-focus-visible:outline-solid peer-focus-visible:outline-offset-2`;

const defaultLabelClass = 'text-component-small font-component-accent leading-component-medium tracking-default';

const defaultIconClass = 'flex items-center justify-center text-current';

const verticalBaseButtonClass = `relative flex flex-col items-start justify-start gap-100 rounded-200 border border-solid
  p-125 transition-colors select-none min-w-dimension-1200 min-h-dimension-1100
  peer-focus-visible:outline peer-focus-visible:outline-solid peer-focus-visible:outline-offset-[3px]
  peer-focus-visible:outline-025 peer-focus-visible:outline-stroke-actionable-alt-pressed`;

const defaultVariantClasses: Record<ChipStatus, Partial<Record<PseudoStates, string>>> = {
  unselected: {
    default: 'bg-surface-transparent text-text-actionable-alt-default border-stroke-actionable-alt-default cursor-pointer',
    hover: 'hover:text-text-actionable-alt-hover hover:border-stroke-actionable-alt-hover',
    active: 'active:text-text-actionable-alt-pressed active:border-stroke-actionable-alt-pressed',
    disabled: 'bg-surface-disabled text-text-disabled border-stroke-actionable-alt-disabled cursor-not-allowed',
  },
  selected: {
    default: 'bg-surface-actionable-alt-selected text-text-inverse border-transparent cursor-pointer',
    hover: 'hover:bg-surface-actionable-alt-hover',
    active: 'active:bg-surface-actionable-alt-pressed',
    disabled: 'bg-surface-actionable-alt-disabled text-text-inverse border-transparent cursor-not-allowed',
  },
};

const verticalVariantClasses: Record<ChipStatus, Partial<Record<PseudoStates, string>>> = {
  unselected: {
    default: 'bg-surface-transparent text-text-actionable-alt-default border-stroke-actionable-alt-default cursor-pointer',
    hover: 'hover:border-stroke-actionable-alt-hover hover:text-text-actionable-alt-hover',
    active: 'active:border-stroke-actionable-alt-pressed active:text-text-actionable-alt-pressed',
    disabled: 'bg-surface-disabled text-text-disabled border-stroke-actionable-alt-disabled elevation-none cursor-not-allowed',
  },
  selected: {
    default: 'bg-surface-actionable-alt-selected text-text-inverse border-transparent elevation-xsmall-soft cursor-pointer',
    hover: 'hover:bg-surface-actionable-alt-hover',
    active: 'active:bg-surface-actionable-alt-pressed',
    disabled: 'bg-surface-actionable-alt-disabled text-text-inverse border-transparent elevation-none cursor-not-allowed',
  },
};
